"""jni_core — Cython runtime shims used by code generated by ``jni-wrap cython``.

Public Python surface is intentionally tiny. Most of the API is the
Cython-level surface exposed by ``core.pxd`` (cimport from generated
``.pyx`` modules).
"""
from __future__ import annotations

__version__ = "0.1.0"


class JavaException(Exception):
    """Raised when a JNI call leaves a pending Java exception.

    The Java exception is described (and cleared) before this is raised.
    """

    def __init__(self, message: str, java_class: str | None = None) -> None:
        super().__init__(message)
        self.java_class = java_class


# Re-export the compiled-side Python entry points so callers can do
# ``from jni_core import get_env``. Imported lazily so importing the
# package does not require a built extension at install-time inspection.
def get_env():  # pragma: no cover - thin shim
    """Return a JNIEnv* wrapper for the current thread (attaching if needed)."""
    from ._core import get_env as _get_env

    return _get_env()


__all__ = ["JavaException", "get_env", "__version__"]
